// ─── INSERT ──────────────────────────────────────────────────────────────────
async function seed() {
  console.log(`Seeding ${meals.length} meals into Supabase...`);

  const rows = meals.map(m => ({
    id: randomUUID(),
    name: m.name,
    author: AUTHOR,
    creator_id: CREATOR_ID,
    ingredients: m.ingredients,
    source: SOURCE,
    recipe: m.recipe,
    story: m.story,
    difficulty: m.difficulty,
    serves: m.serves,
    tags: m.tags,
    photo_url: null,
    created_at: randDate(),
  }));

  const BATCH = 50;
  let inserted = 0;
  for (let offset = 0; offset < rows.length; offset += BATCH) {
    const batch = rows.slice(offset, offset + BATCH);
    const { error } = await supabase.from('preset_meals').insert(batch);
    if (error) {
      console.error(`Batch starting at ${offset} failed:`, error.message);
      process.exit(1);
    }
    inserted += batch.length;
    console.log(`  ✓ Inserted ${inserted}/${rows.length}`);
  }

  console.log(`\nDone! ${inserted} meals seeded.`);
}

seed().catch(err => { console.error(err); process.exit(1); });
